package com.example.demo.models;import jakarta.persistence.*;import lombok.*;import java.io.Serializable;
@Entity @Table(name="permisos_usuario") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder @IdClass(PermisoUsuario.Clave.class) public class PermisoUsuario{@jakarta.persistence.Id @ManyToOne(fetch=FetchType.LAZY)@JoinColumn(name="persona_id")private Persona persona;@jakarta.persistence.Id @Enumerated(EnumType.STRING)private Permiso permiso;public enum Permiso{MODIFICAR_PRECIOS,APLICAR_DESCUENTOS,ANULAR_VENTAS,REALIZAR_DEVOLUCIONES,AJUSTAR_STOCK,REGISTRAR_COMPRAS,VER_REPORTES,ADMINISTRAR_CLIENTES,COBRAR_CUENTAS,GESTIONAR_CAJA} @Data @NoArgsConstructor @AllArgsConstructor public static class Clave implements Serializable{private Long persona;private Permiso permiso;}}
